useEffect(() => {
  const timerId = setInterval(() => console.log('Тик'), 1000);

  // Функция очистки (возвращаемая функция)
  return () => {
    clearInterval(timerId); // Вызовется перед размонтированием
    console.log('Компонент удаляется (аналог componentWillUnmount)');
  };
}, []);
```
